module shift_register (
    input clk,
    input shift_enable,
    input load_enable,
    input [7:0] data_in,
    output [7:0] data_out );reg [7:0] shadow;

always @(posedge clk) begin
    if (load_enable)
        shadow <= data_in;
    else if (shift_enable)
        shadow <= {shadow[6:0], 1'b0};
end

assign data_out = shadow;

endmodule
